      decRight[i] = decRight[i + 1] + 1;
    }
  }

  // Precompute for each index the longest increasing sequence starting at that index
  const incStart = new Array(n).fill(0);
  incStart[n - 1] = 1;
  for (let i = n - 2; i >= 0; i--) {
    incStart[i] = 1;
    if (nums[i] < nums[i + 1]) {
      incStart[i] = incStart[i + 1] + 1;
    }
