      for (let q = p + 1; q < n - 1; q++) {
        if (nums[q] >= nums[q - 1]) {
          continue;
        }
        for (let r = q + 1; r < n; r++) {
          if (nums[r] <= nums[r - 1]) {
            continue;
          }
          // Check if the middle part is strictly decreasing
          if (nums[q] >= nums[q - 1]) {
            continue;
          }
          // Calculate the sum of the triplet
          let sum = 0;
          for (let i = l; i <= r; i++) {
            sum += nums[i];
          }
          maxSum = Math.max(maxSum, sum);
        }
      }
    }
  }

  return maxSum;
}
